            long v = edges[i][1];
            long w = edges[i][2];
            adj.get((int) u).add(new Edges((int) v, w));
        }

        // Dijkstra's algorithm with state (node, hasSwitchUsed)
        PriorityQueue<State> pq = new PriorityQueue<>((a, b) -> Long.compare(a.cost, b.cost));
        pq.offer(new State(0, false, 0));

        boolean[] visited = new boolean[(int) n];
        long[] dist = new long[(int) n];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int node = current.node;
            boolean hasSwitchUsed = current.hasSwitchUsed;
            long cost = current.cost;

            if (node == n - 1) {
                return cost;
            }

            if (visited[node] && hasSwitchUsed) {
                continue;
            }
            visited[node] = true;

            for (Edges edge : adj.get(node)) {
                int v = edge.v;
                long w = edge.w;

                // Regular move
                if (dist[v] > dist[node] + w) {
                    dist[v] = dist[node] + w;
                    pq.offer(new State(v, hasSwitchUsed, dist[v]));
                }

                // Reverse the edge if switch is not used
                if (!hasSwitchUsed) {
                    long reversedCost = dist[node] + 2 * w;
                    if (dist[v] > reversedCost) {
                        dist[v] = reversedCost;
                        pq.offer(new State(v, true, dist[v]));
                    }
                }
            }
        }

        return -1;
    }

    static class Edges {
        int v;
        long w;

        Edges(int v, long w) {
            this.v = v;
            this.w = w;
        }
    }

    static class State {
        int node;
        boolean hasSwitchUsed;
        long cost;

        State(int node, boolean hasSwitchUsed, long cost) {
            this.node = node;
            this.hasSwitchUsed = hasSwitchUsed;
