    }

    for (int i = 0; i < edgeCount; i++) {
        long u = edges[i][0];
        long v = edges[i][1];
        long w = edges[i][2];
        adj.get((int) u).add(new int[]{(int) v, (int) w});
    }

    // Dijkstra's algorithm with state (node, hasSwitchUsed)
    // We use a priority queue with (cost, node, hasSwitchUsed)
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
    pq.offer(new long[]{0, 0, 0}); // (cost, node, hasSwitchUsed)

    // Distance array: distance[node][hasSwitchUsed]
    long[][] dist = new long[nodeCount][2];
    for (int i = 0; i < nodeCount; i++) {
        Arrays.fill(dist[i], Long.MAX_VALUE);
    }
    dist[0][0] = 0;

    while (!pq.isEmpty()) {
        long cost = pq.peek()[0];
        int node = (int) pq.peek()[1];
        int hasSwitchUsed = (int) pq.peek()[2];
        pq.poll();

        if (node == nodeCount - 1) {
            return cost;
        }

        if (cost > dist[node][hasSwitchUsed]) {
            continue;
        }

        // Traverse original edges
        for (int[] edge : adj.get(node)) {
            int v = edge[0];
            int w = edge[1];
            long newCost = cost + w;
            if (newCost < dist[v][hasSwitchUsed]) {
                dist[v][hasSwitchUsed] = newCost;
                pq.offer(new long[]{newCost, v, hasSwitchUsed});
            }
        }

        // Check if we can flip the switch at this node
        if (!hasSwitchUsed) {
            // Flip the switch: reverse the incoming edge
            // We need to find the incoming edge to this node
            // Since the graph is directed, we need to check all edges that point to this node
            for (int i = 0; i < edgeCount; i++) {
                long u = edges[i][0];
                long v = edges[i][1];
                if (v == node) {
                    long w = edges[i][2];
