                    if (newCost < dist[node][1]) {
                        dist[node][1] = newCost;
                        pq.offer(new long[]{newCost, node, 1});
                    }
                }
            }
        }
    }

    // If we can't reach the destination
    for (int i = 0; i < nodeCount; i++) {
        if (dist[nodeCount - 1][i] != Long.MAX_VALUE) {
            return dist[nodeCount - 1][i];
        }
    }

    return -1;
}
